INSERT INTO [Purch_ Price Model Item] ( [Model Item No_], [Vendor No_], [Starting Date], [Currency Code], [Unit of Measure Code], [Minimum Quantity], [Constant Variable Code], [Variable Code 01], [Variable Code 02], [selling season code], [Ending Date], [Constant Assortment Var_Grp_], [Variable Group 01], [Variable Group 02], [Direct Unit Cost] )
SELECT ValutazioneMagazzino_GenerazioneVALA_ModelItem_s0.[Model Item No_], "VAL A" AS NewVendor, [forms]![principale]![DataCreazioneValoriMagazzino] AS NewDate, "" AS NewCurrency, ValutazioneMagazzino_GenerazioneVALA_ModelItem_s0.[Unit of Measure Code], ValutazioneMagazzino_GenerazioneVALA_ModelItem_s0.[Minimum Quantity], ValutazioneMagazzino_GenerazioneVALA_ModelItem_s0.[Constant Variable Code], ValutazioneMagazzino_GenerazioneVALA_ModelItem_s0.[Variable Code 01], ValutazioneMagazzino_GenerazioneVALA_ModelItem_s0.[Variable Code 02], "" AS [Selling Season Code], ValutazioneMagazzino_GenerazioneVALA_ModelItem_s0.[Ending Date], ValutazioneMagazzino_GenerazioneVALA_ModelItem_s0.[Constant Assortment Var_Grp_], ValutazioneMagazzino_GenerazioneVALA_ModelItem_s0.[Variable Group 01], ValutazioneMagazzino_GenerazioneVALA_ModelItem_s0.[Variable Group 02], IIf([Currency Code]="USD",Round(Val([Direct Unit Cost])/[forms]![principale]![tassodicambiovalutazionemagazzino],2),[Direct Unit Cost]) AS NewDirectUnitCost
FROM ((ValutazioneMagazzino_GenerazioneVALA_ModelItem_s0 LEFT JOIN [ValutazioneMagazzino_GenerazioneVALA_ModelItem-VALA-GiaPresenti] ON ValutazioneMagazzino_GenerazioneVALA_ModelItem_s0.[Model Item No_] = [ValutazioneMagazzino_GenerazioneVALA_ModelItem-VALA-GiaPresenti].[Model Item No_]) LEFT JOIN [ValutazioneMagazzino_GenerazioneVALA_ModelItem-PrezziMultipli] ON ValutazioneMagazzino_GenerazioneVALA_ModelItem_s0.[Model Item No_] = [ValutazioneMagazzino_GenerazioneVALA_ModelItem-PrezziMultipli].[Model Item No_]) INNER JOIN ValutazioneMagazzino_Support_DeterminazioneCodiciGiacenti ON ValutazioneMagazzino_GenerazioneVALA_ModelItem_s0.[Model Item No_] = ValutazioneMagazzino_Support_DeterminazioneCodiciGiacenti.[Model Item No_]
WHERE ((([ValutazioneMagazzino_GenerazioneVALA_ModelItem-VALA-GiaPresenti].[Model Item No_]) Is Null) AND ((ValutazioneMagazzino_GenerazioneVALA_ModelItem_s0.[Vendor No_])<>"VAL B") AND (([ValutazioneMagazzino_GenerazioneVALA_ModelItem-PrezziMultipli].[Model Item No_]) Is Null));

